const fs = require('fs');
const path = require('path');

const migrationsDir = path.join(__dirname, 'migrations');

// Read all SQL files from the migrations directory
fs.readdir(migrationsDir, (err, files) => {
  if (err) {
    if (err.code === 'ENOENT') {
      console.log('Migrations directory does not exist.');
      return;
    }
    console.error('Error reading migrations directory:', err);
    return;
  }

  // Filter and sort SQL files by filename
  const sqlFiles = files
    .filter(file => path.extname(file).toLowerCase() === '.sql')
    .sort();

  // Log each migration file that would be applied
  console.log('Migrations to apply:');
  sqlFiles.forEach(file => {
    console.log(`- Applying migration: ${file}`);
  });

  if (sqlFiles.length === 0) {
    console.log('No SQL migration files found.');
  }
});

