// migrate.js
const fs = require('fs');
const path = require('path');

// Directory containing migration SQL files
class Migrate {
  constructor(migrationDir = './migrations') {
    this.migrationDir = path.resolve(migrationDir);
  }

  // Read all SQL files from the migrations directory in sorted order
  getMigrationFiles() {
    try {
      const files = fs.readdirSync(this.migrationDir);
      // Filter only .sql files and sort them alphabetically
      return files
        .filter(file => path.extname(file).toLowerCase() === '.sql')
        .sort()
        .map(file => path.join(this.migrationDir, file));
    } catch (err) {
      console.error(`Error reading migration directory ${this.migrationDir}:`, err.message);
      process.exit(1);
    }
  }

  // Simulate applying migrations
  run() {
    const migrationFiles = this.getMigrationFiles();

    if (migrationFiles.length === 0) {
      console.log('No migration files found.');
      return;
    }

    console.log('Applying migrations in order:');
    migrationFiles.forEach(file => {
      console.log(`Applying: ${path.basename(file)}`);
      // In a real script, you would read and execute the SQL here
    });

    console.log('Migration process completed.');
  }
}

// Run migration
if (require.main === module) {
  const migrator = new Migrate();
  migrator.run();
}

module.exports = Migrate;

